import{c as a,Z as n,Q as s,j as r,g as t,n as i,o as h,m as d}from"./chunks/framework.BPKcPtvA.js";const f=JSON.parse('{"title":"Before you begin","description":"What you need to test MuHaven — a browser, a passkey, ~10–15 minutes, and testnet funds. No install, no ETH.","frontmatter":{"title":"Before you begin","description":"What you need to test MuHaven — a browser, a passkey, ~10–15 minutes, and testnet funds. No install, no ETH."},"headers":[],"relativePath":"guide/before-you-begin.md","filePath":"guide/before-you-begin.md","lastUpdated":1780203186000}'),l={name:"guide/before-you-begin.md"};function u(p,e,c,y,m,g){const o=n("TaskMeta");return s(),r("div",null,[e[0]||(e[0]=t("h1",{id:"before-you-begin",tabindex:"-1"},[i("Before you begin "),t("a",{class:"header-anchor",href:"#before-you-begin","aria-label":'Permalink to "Before you begin"'},"​")],-1)),e[1]||(e[1]=t("p",null,"You can test all of MuHaven from a browser. There is nothing to install.",-1)),h(o,{time:"~2 min to read",role:"Anyone",needs:"A modern browser + a passkey device"}),e[2]||(e[2]=d('<h2 id="what-you-need" tabindex="-1">What you need <a class="header-anchor" href="#what-you-need" aria-label="Permalink to &quot;What you need&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Detail</th></tr></thead><tbody><tr><td><strong>A modern browser</strong></td><td>Chrome, Edge, Safari, or Firefox — recent version.</td></tr><tr><td><strong>A passkey device</strong></td><td>Touch ID / Face ID on a Mac or iPhone, Windows Hello, an Android phone, or a hardware security key. This <em>is</em> your login — there&#39;s no password.</td></tr><tr><td><strong>Testnet USDC</strong></td><td>Free from a faucet — see <a href="/guide/investor/get-funds">Get testnet funds</a>.</td></tr><tr><td><strong>~10–15 minutes</strong></td><td>The <a href="/guide/happy-path">happy path</a> takes about 10.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Easiest passkey option on Chrome/Android</p><p>When your device prompts you to save the passkey, choose <strong>Google Password Manager</strong> — it stores the passkey in your Google account and syncs it across devices, so you don&#39;t need a hardware key or a specific OS. It&#39;s the smoothest option for testing.</p></div><div class="tip custom-block"><p class="custom-block-title">You do NOT need ETH or any gas token.</p><p>MuHaven uses an <a href="/get-started/passkey-accounts">ERC-4337 smart account</a> with <strong>sponsored gas</strong>. Your transactions are paid for by the platform&#39;s paymaster, so you never buy or hold ETH. The only testnet token you ever need is <strong>USDC</strong>, and that&#39;s free from a faucet.</p></div><h2 id="how-the-money-works-testnet" tabindex="-1">How the money works (testnet) <a class="header-anchor" href="#how-the-money-works-testnet" aria-label="Permalink to &quot;How the money works (testnet)&quot;">​</a></h2><p>Everything is play-money on <strong>Arbitrum Sepolia</strong>:</p><ol><li>You get free <strong>testnet USDC</strong> from a faucet.</li><li>Inside MuHaven you convert it to <strong>mhUSDC</strong> — a <em>confidential</em> USDC wrapper whose balance is encrypted on-chain. mhUSDC is the currency you buy positions and receive yield in. (<a href="/get-started/privacy-boundary">Why &quot;mhUSDC&quot;?</a>)</li><li>When you&#39;re done you can convert mhUSDC back to USDC.</li></ol><p>No real funds are ever at risk.</p><h2 id="the-privacy-idea-in-one-paragraph" tabindex="-1">The privacy idea in one paragraph <a class="header-anchor" href="#the-privacy-idea-in-one-paragraph" aria-label="Permalink to &quot;The privacy idea in one paragraph&quot;">​</a></h2><p>MuHaven holds your token balances <strong>encrypted on-chain</strong> using Fhenix CoFHE (homomorphic encryption). Other people — including the platform operator — see that you hold <em>something</em>, but not <em>how much</em>. <strong>You</strong> decrypt your own numbers locally with a one-tap permit when you want to see them. That &quot;reveal&quot; moment is the privacy <em>aha</em> the guide keeps pointing you at — most visibly in <a href="/guide/investor/buy">Buy a position</a> and <a href="/guide/investor/reveal-balance">Reveal your balance</a>.</p><h2 id="a-few-things-that-will-save-you-time" tabindex="-1">A few things that will save you time <a class="header-anchor" href="#a-few-things-that-will-save-you-time" aria-label="Permalink to &quot;A few things that will save you time&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Register a fresh passkey on the real domain</p><p>A passkey is bound to the exact website domain where you create it (WebAuthn &quot;RP ID&quot;). A passkey made on a staging or local URL <strong>will not</strong> work on the production app, and vice-versa. Always register at the URL you intend to test on — for the public app that&#39;s <a href="https://muhaven.app" target="_blank" rel="noreferrer"><strong>muhaven.app</strong></a>. See <a href="/guide/troubleshooting#passkey-rp-id">Troubleshooting</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">Encrypted balances need a &quot;reveal&quot; before some actions</p><p>Because balances are encrypted, the app sometimes can&#39;t tell whether you have enough to proceed (e.g. buying) until you reveal. When that happens you&#39;ll see an inline <strong>Reveal</strong> button — one tap, no transaction, no on-chain leak. This is expected, not an error.</p></div><div class="tip custom-block"><p class="custom-block-title">Some steps are intentionally async (~30–60s, occasionally minutes)</p><p>On-chain transactions take a block to confirm, and a few flows (yield distribution, withdrawing mhUSDC back to USDC) involve a homomorphic-decryption round-trip that adds a short wait. Each page tells you what to expect.</p></div><p>→ Next: <a href="/guide/happy-path"><strong>The 10-minute happy path</strong></a></p>',15))])}const v=a(l,[["render",u]]);export{f as __pageData,v as default};
